INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-a5729396-moex-00494', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '「旅行的荒謬和驚喜在我們必須千里跋涉以換取『在』的心境。必須到一個遙遠陌生的地方以實現生 命在現實中失落或從來欠缺的氣象：一種美，一種境界。」 下列選項，何者不能與此文中「在」的觀點相通？', '["在一個陌生的地方，走過陌生的街道，以平常沒有的雍容和悠閒，不急著到哪裡去", "我迷上了喜馬拉雅的國度，西藏、不丹、印度拉達克，站在陡峭銳利寸草不生的山稜上，八方空漠， 一切話語皆失去了意義。無聲的涅槃", "生活在他方，歇腳只不過是一時的權宜之計罷了，我們總是還來不及往土裡面扎根，就又要倉皇地 拎起行囊，在時間和空間的夾縫之中逃遁", "旅途中變化無窮的景致，未必能轉移你固執的視點而達至所謂的「目不暇給」。看東看西一陣後， 你總還是看回你自己、看回你心中一直還企盼的某一世界"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00495', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '「黑猩猩活在『當下、眼前』的世界裡，也因為這樣，非常善於記憶眼前瞬間出現的數字。他們絕不 會像人類一樣，考慮百年後的未來，或是緬懷百年前的歷史。所以人類會對未來懷抱希望——無論處 在多麼艱困的情況下，都能抱持勇氣。人，何以為人？那就是想像的力量。」下列選項，最接近本文 旨意的是：', '["人類擁有想像力，具備想像未來的力量，才能懷抱希望開創潛能", "黑猩猩的特質就是活在當下，不計較得失，也就沒有恐懼與失望", "黑猩猩因活在當下，所以沒有對未來的憂慮，值得我們人類效法", "人類因擁有想像力，無法像黑猩猩只活在當下，所以會悲傷焦慮"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00496', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '「因為噪音，讓我們拒絕聆聽。也因為拒絕聆聽，我們連擁有什麼，或是失去什麼都不知道。因為我 們不善於聆聽，也無法解讀聲音背後的訊息與力量。志銘在書上寫著：『聽聞鳥鳴聲背後所代表的意 義，毋寧更取決於當時的社會環境。』不懂得聆聽鳥語，是否也是我們這個世代的失落呢？如今，我 們應該努力去做的，是找回屬於這片土地的聲音。不論是自然天籟或是人文上的音景。這些資料，有 著文化創造與美學建構上的意義，更重要的是，留下這些歷史的跫音，讓我們不僅有了回味的空間， 也可以展現歲月演進的痕跡。」本文主旨是：', '["不論社會環境如何改變，大多數人對於欣賞聲景的態度都不會動搖", "不論是自然或人文的聲景，都具有值得去品味、感受的訊息與力量", "社會經濟環境的不同，必然影響人們養鳥的意願及欣賞鳥語的態度", "只要大家懂得聆聽土地的聲音，就能不斷創造出新的社會聲情文化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00497', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '臺北市政府要求轄下各機關免用一次性餐具，發文時應採用的公文類別是：', '["呈", "函", "咨", "簽"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00498', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '下列期望語之使用，錯誤的是：', '["「請鑒核」是指請受文者核定，多使用在下行文", "「請照辦」是請受文者依文照辦，多使用在下行文", "「希辦理見復」是請受文者辦妥後回復，多使用在下行文", "「請備查」是在決定某項事情之後，行文向受文者報備，多使用在上行文"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00499', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '「公文用語」中的「臺端」，下列選項敘述正確的是：', '["臺北市長發函給高雄市長時的稱謂語", "信義區公所發文給轄區民眾時的稱謂語", "國立臺灣大學對教育部行文時的稱謂語", "臺北市松山區公所對臺北市政府復文時的稱謂語"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00500', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '公文中關於副本使用之注意事項，下列選項何者正確？', '["如正本附送附件，副本須比照辦理", "副本如附送附件，無須再額外作任何說明", "凡接到副本，為表示明確態度，皆須回覆原單位", "若情況緊急，需越級行文時，得以副本抄送其直屬上級機關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00501', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '關於移送管轄，下列敘述何者正確？', '["法院得依原告或被告之聲請，以裁定移送至有管轄權之法院", "對於法院駁回移送訴訟之聲請所為裁定，不得聲明不服", "對於法院准許移送訴訟所為裁定，不得聲明不服", "受移送之法院應受移送裁定之羈束，於訴訟專屬於他法院管轄之情形，受移送之法院不得再移送至該專 屬管轄之法院"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00502', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '關於因侵權行為涉訟之管轄，下列敘述何者正確？', '["得由原告住所地之法院管轄", "應由被告住所地之法院專屬管轄", "應由行為結果發生地之法院專屬管轄", "得由實行行為地法院管轄"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00503', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '下列何者，無當事人能力？', '["清算中之A公司", "臺北市政府警察局士林分局文林路派出所", "臺灣臺北地方法院", "財團法人B醫院"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
